module RefModule(
  input [7:0] input_vector,
  output reg [7:0] output_vector
);integer obf_i;

  always @ (input_vector) begin
    for (obf_i = 0; obf_i < 8; obf_i = obf_i + 2) begin
      output_vector[obf_i] = input_vector[obf_i+1];
      output_vector[obf_i+1] = input_vector[obf_i];
    end
  end

endmodule
